const genericTrap = "비교 기간과 전달 시차를 확인하지 않고 이 변화가 경제와 아무 관계가 없다고 본다";

export const expandedScenarioQuestions = scenarioGroups.flatMap((group, groupIndex) =>
  group.cases.map((entry, caseIndex) => {
    const [slug, condition, correct, temptingWrong, mechanism, check] = entry;
    const globalIndex = groupIndex * 20 + caseIndex;
    const answerIndex = globalIndex % 4;
    const choices = [temptingWrong, group.commonTrap, genericTrap];
    choices.splice(answerIndex, 0, correct);

    return {
      id: `scenario-${group.prefix}-${slug}`,
      type: "scenario",
      category: group.category,
      difficulty: globalIndex % 2 === 0 ? "중급" : "심화",
      prompt: `${condition} 이때 가장 합리적인 판단은 무엇일까요?`,
      context: `${condition} 다른 조건과 지속 기간, 비교 기준은 아직 모두 확인되지 않았습니다.`,
      choices,
      answerIndex,
      explanation: `${mechanism} 따라서 ${correct}. 판단할 때는 ${check} 확인해야 결론의 신뢰도를 높일 수 있습니다.`,
      rule: `판단 전 ${check} 확인하고 반대 신호가 나오면 결론을 다시 조정합니다.`
    };
  })
);
